parameters.jsCode:
// ============================================================
// Build CEGID customer payload from a Shopify customer webhook
// ------------------------------------------------------------
// Maps the incoming Shopify customer (individual OR company)
// to the JSON structure expected by the CEGID Y2 customers API.
// ============================================================

// --- Inputs ---
const cegidConfig      = $('Set CEGID Config').first().json; // CEGID config (store, tax system, etc.)
const shopifyCustomer  = $json.body;                          // Shopify customer payload
const shopifyAddress   = shopifyCustomer.default_address || {}; // Default address (may be missing)

// A customer is treated as a company if the address carries a company name,
// otherwise as an individual.
const isCompany = !!shopifyAddress.company;

// --- Address block (REQUIRED by the CEGID API) ---
// The API rejects the payload without an address block containing at least one line.
// Collect every non-empty address line, numbering them sequentially ('1', '2', ...).
const addressLines = [shopifyAddress.address1, shopifyAddress.address2]
  .filter(Boolean)
  .map((value, i) => ({ id: String(i + 1), value }));

// Fallback: if Shopify sent no address line at all, insert a placeholder
// so the required line '1' is always present and passes the API's non-empty check.
// (A blank space is rejected — the API trims and treats it as empty — so we use a visible dash.)
if (addressLines.length === 0) {
  addressLines.push({ id: '1', value: '-' });
}

const cegidAddress = {
  countryId: cegidConfig.default_country,
  notAtThisAddress: false,
  optinPostal: 'AskCustomer',
  city: shopifyAddress.city,
  zipCode: shopifyAddress.zip,
  lines: addressLines
};

// --- Customer identity block (individual OR company) ---
// CEGID expects either an "individual" or a "company" key at the top level,
// never both. We build the matching one based on whether a company name is present.
const customerIdentity = isCompany
  ? {
      company: {
        name: shopifyAddress.company,
        communication: {
          mailing: false,
          emailing: false,
          // Company uses a single email OBJECT (only included when an email exists,
          // to stay consistent with the API's coherence checks)
          ...(shopifyCustomer.email ? { email: { value: shopifyCustomer.email, validity: shopifyCustomer.verified_email ? 'Valid' : 'NotValid', optin: 'AskCustomer' } } : {}),
          ...(shopifyCustomer.phone ? { phones: [{ type: 'Phone1', value: shopifyCustomer.phone, validity: 'Valid', optin: 'AskCustomer' }] } : {})
        }
      }
    }
  : {
      individual: {
        firstName: shopifyCustomer.first_name,
        lastName: shopifyCustomer.last_name,
        communication: {
          mailing: false,
          emailing: false,
          // emailRecovery must stay consistent with the presence of an email:
          // the API rejects emailRecovery: true when no email is provided.
          emailRecovery: !!shopifyCustomer.email,
          // Individual uses an emails ARRAY
          ...(shopifyCustomer.email ? { emails: [{ id: '1', value: shopifyCustomer.email, validity: shopifyCustomer.verified_email ? 'Valid' : 'NotValid', optin: 'AskCustomer' }] } : {}),
          ...(shopifyCustomer.phone ? { phones: [{ type: 'Cellular', value: shopifyCustomer.phone, validity: 'Valid', optin: 'AskCustomer' }] } : {})
        }
      }
    };

// --- Assemble final payload ---
const payload = {
  identifier: { externalReference: String(shopifyCustomer.id) },
  closed: false,
  creationStoreIdentifier: { id: cegidConfig.default_store },
  usualStoreIdentifier: { id: cegidConfig.default_store },
  taxExcluded: shopifyCustomer.tax_exempt,
  fictitious: false,
  prospect: false,
  identification: { shortName: String(shopifyCustomer.id) },
  informations: {
    currencyId: cegidConfig.default_currency,
    taxSystemId: cegidConfig.tax_system_id,
    ...(shopifyCustomer.note ? { description: shopifyCustomer.note } : {})
  },
  address: cegidAddress, // always included — required by the API
  ...customerIdentity    // spreads either "individual" or "company" at the top level
};

return { json: payload };
